/**
 * n8n Function / Code node (JavaScript)
 * Input: items[0].json.output is a STRING that contains JSON.
 * Goal: Parse it into an object and return a clean structured output.
 */

function safeJsonParse(str) {
  try {
    return { ok: true, data: JSON.parse(str) };
  } catch (err) {
    return { ok: false, error: err?.message || String(err) };
  }
}

const item = items[0]?.json || {};
const outputStr = item.output;

// Validate input
if (typeof outputStr !== "string" || outputStr.trim().length === 0) {
  return [
    {
      json: {
        ok: false,
        error: "Missing or invalid 'output' field. Expected a non-empty JSON string in items[0].json.output.",
        raw: item,
      },
    },
  ];
}

// Parse the JSON string inside "output"
const parsed = safeJsonParse(outputStr);

if (!parsed.ok) {
  return [
    {
      json: {
        ok: false,
        error: "Failed to parse items[0].json.output as JSON string.",
        parse_error: parsed.error,
        output_preview: outputStr.slice(0, 500),
      },
    },
  ];
}

// Optional: basic schema safety checks
const data = parsed.data;
const confidence = data?.qa?.confidence_score ?? null;

// Create a final clean payload (customize as you like)
return [
  {
    json: {
      ok: true,
      request: data.request || {},
      research: data.research || {},
      draft: data.draft || {},
      qa: data.qa || {},
      final_content: data?.qa?.final_content || data?.draft?.content || "",
      confidence_score: typeof confidence === "number" ? confidence : null,
    },
  },
];
